from board import Board
from player import Player

class Game:
    def __init__(self):
        self.board = Board()
        self.player_turn = 'white'

    def start(self):
        while not self.is_game_over():
            self.print_board()
            from_pos, to_pos = input(f"Player {self.player_turn} move (from-to): ").split('-')
            if self.is_valid_move(from_pos, to_pos):
                self.move_piece(from_pos, to_pos)
                if self.player_turn == 'white':
                    self.player_turn = 'black'
                else:
                    self.player_turn = 'white'
            else:
                print("Invalid move. Try again.")
        self.print_board()
        winner = self.check_win_condition()
        if winner:
            print(f"Player {winner} wins!")
        else:
            print("It's a draw!")

    def is_valid_move(self, from_pos, to_pos):
        return self.board.is_valid_move(from_pos, to_pos, self.player_turn)

    def move_piece(self, from_pos, to_pos):
        self.board.move_piece(from_pos, to_pos, self.player_turn)

    def capture_piece(self, from_pos, to_pos):
        self.board.capture_piece(from_pos, to_pos, self.player_turn)

    def is_game_over(self):
        return self.check_win_condition() or not self.board.has_valid_moves(self.player_turn)

    def check_win_condition(self):
        if self.board.king_exists('black'):
            return 'white'
        elif self.board.king_exists('white'):
            return 'black'
        elif not self.board.has_valid_moves(self.player_turn):
            return 'draw'
        return None

    def print_board(self):
        self.board.print_board()
