#### Board Class

```python
from piece import Piece, WHITE, BLACK, EMPTY

class Board:
    def __init__(self):
        self.board = [[EMPTY for _ in range(8)] for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        for row in range(3):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = Piece(row, col, BLACK)
        for row in range(5, 8):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = Piece(row, col, WHITE)

    def is_valid_move(self, from_pos, to_pos, player_color):
        if (int(from_pos[0]), int(from_pos[1])) != (int(to_pos[0]), int(to_pos[1])):
            piece = self.get_piece(from_pos)
            if piece and piece.color == player_color:
                dx, dy = abs(int(from_pos[0]) - int(to_pos[0])), abs(int(from_pos[1]) - int(to_pos[1]))
                if (dx, dy) in [(1, 1), (2, 2)]:
                    if self.is_valid_capture(from_pos, to_pos):
                        return True
        return False

    def move_piece(self, from_pos, to_pos, player_color):
        piece = self.get_piece(from_pos)
        if piece and piece.color == player_color:
            dx, dy = int(to_pos[0]) - int(from_pos[0]), int(to_pos[1]) - int(from_pos[1])
            new_position = (int(from_pos[0]) + dx, int(from_pos[1]) + dy)
            self.board[new_position[0]][new_position[1]] = piece
            self.board[int(from_pos[0])][int(from_pos[1])] = EMPTY

    def capture_piece(self, from_pos, to_pos, player_color):
        piece = self.get_piece(from_pos)
        if piece and piece.color == player_color:
            dx, dy = int(to_pos[0]) - int(from_pos[0]), int(to_pos[1]) - int(from_pos[1])
            capture_position = (int(from_pos[0]) + dx // 2, int(from_pos[1]) + dy // 2)
            self.board[capture_position[0]][capture_position[1]] = EMPTY
            new_position = (int(from_pos[0]) + dx, int(from_pos[1]) + dy)
            piece.captures += 1
            if piece.type == 'normal' and capture_position[0] in [0, 7]:
                piece.promote()
            self.board[new_position[0]][new_position[1]] = piece

    def is_valid_capture(self, from_pos, to_pos):
        dx, dy = int(to_pos[0]) - int(from_pos[0]), int(to_pos[1]) - int(from_pos[1])
        capture_position = (int(from_pos[0]) + dx // 2, int(from_pos[1]) + dy // 2)
        if self.get_piece(capture_position) and self.get_piece(capture_position).color != self.get_piece(from_pos).color:
            return True
        return False

    def get_piece(self, position):
        return self.board[int(position[0])][int(position[1])]

    def has_valid_moves(self, player_color):
        for row in range(8):
            for col in range(8):
                piece = self.get_piece((str(row), str(col)))
                if piece and piece.color == player_color:
                    moves = [(row + 1, col - 1), (row + 1, col + 1)]
                    if piece.type == 'king':
                        moves += [(row - 1, col - 1), (row - 1, col + 1)]
                    for move in moves:
                        if self.is_valid_move((str(row), str(col)), str(move[0]) + '-' + str(move[1]), player_color):
                            return True
        return False

    def king_exists(self, color):
        for row in range(8):
            for col in range(8):
                piece = self.get_piece((str(row), str(col)))
                if piece and piece.color == color and piece.type == 'king':
                    return True
        return False

    def print_board(self):
        from colorama import Fore, Style
        pieces = {
            EMPTY: ' ',
            Piece(WHITE, 0, 'normal'): Fore.CYAN + 'W' + Style.RESET_ALL,
            Piece(WHITE, 0, 'king'): Fore.CYAN + 'WK' + Style.RESET_ALL,
            Piece(BLACK, 0, 'normal'): Fore.MAGENTA + 'B' + Style.RESET_ALL,
            Piece(BLACK, 0, 'king'): Fore.MAGENTA + 'BK' + Style.RESET_ALL
        }
        for row in range(8):
            print(' '.join(pieces.get(piece, ' ') for piece in self.board[row]))
